blocks.body:
{
    "level": "A1–B1",
    "intro": "W tym temacie poznasz <strong>najważniejsze typy zaimków w języku angielskim</strong> i zobaczysz, kiedy używamy każdej z tych form.",
    "rules": [
        {
            "label": "Personal",
            "color": "emerald",
            "text": "<strong>zaimki osobowe</strong> — kto coś robi albo kogo dotyczy czynność:",
            "example": "I work. She reads. They play."
        },
        {
            "label": "Possessive",
            "color": "blue",
            "text": "<strong>formy dzierżawcze</strong> — czyje to jest:",
            "example": "my book, mine, his, hers"
        },
        {
            "label": "Reflexive",
            "color": "amber",
            "text": "<strong>zaimki zwrotne</strong> — gdy czynność wraca do tej samej osoby:",
            "example": "I did it myself. She taught herself."
        }
    ]
}

{
    "title": "1. Typy zaimków",
    "intro": "W angielskim spotkasz kilka podstawowych grup zaimków:",
    "items": [
        {
            "label": "Personal",
            "title": "Osobowe",
            "subtitle": "I, you, he, she, it, we, they — kto działa albo kto otrzymuje czynność"
        },
        {
            "label": "Possessive",
            "title": "Dzierżawcze",
            "subtitle": "my / mine, your / yours, his, her / hers — czyje to jest"
        },
        {
            "label": "Reflexive",
            "title": "Zwrotne",
            "subtitle": "myself, yourself, himself, herself — czynność skierowana na siebie"
        },
        {
            "label": "Demonstrative",
            "title": "Wskazujące",
            "subtitle": "this, that, these, those — wskazują osobę albo rzecz"
        },
        {
            "label": "Indefinite",
            "title": "Nieokreślone",
            "subtitle": "someone, anybody, nothing — osoba albo rzecz bez doprecyzowania"
        },
        {
            "label": "Relative",
            "title": "Względne",
            "subtitle": "who, which, that — łączą części zdania"
        }
    ]
}

{
    "title": "2. Zaimki osobowe",
    "sections": [
        {
            "label": "Subject pronouns",
            "color": "emerald",
            "description": "Tych form używamy jako <strong>podmiotu</strong>, czyli osoby lub rzeczy wykonującej czynność.",
            "examples": [
                {
                    "en": "I work every day.",
                    "ua": "Pracuję codziennie."
                },
                {
                    "en": "You are smart.",
                    "ua": "Jesteś bystry."
                },
                {
                    "en": "He reads books.",
                    "ua": "On czyta książki."
                },
                {
                    "en": "She likes music.",
                    "ua": "Ona lubi muzykę."
                },
                {
                    "en": "It is a cat.",
                    "ua": "To jest kot."
                },
                {
                    "en": "We are friends.",
                    "ua": "Jesteśmy przyjaciółmi."
                },
                {
                    "en": "They play football.",
                    "ua": "Oni grają w piłkę nożną."
                }
            ]
        },
        {
            "label": "Object pronouns",
            "color": "sky",
            "description": "Tych form używamy jako <strong>dopełnienia</strong>, czyli gdy ktoś lub coś otrzymuje czynność.",
            "examples": [
                {
                    "en": "Call me later.",
                    "ua": "Zadzwoń do mnie później."
                },
                {
                    "en": "I see you.",
                    "ua": "Widzę cię."
                },
                {
                    "en": "She loves him.",
                    "ua": "Ona go kocha."
                },
                {
                    "en": "I know her.",
                    "ua": "Znam ją."
                },
                {
                    "en": "Give it to me.",
                    "ua": "Daj mi to."
                },
                {
                    "en": "They invited us.",
                    "ua": "Zaprosili nas."
                },
                {
                    "en": "I like them.",
                    "ua": "Lubię ich."
                }
            ]
        },
        {
            "label": "Tabela form osobowych",
            "color": "purple",
            "description": "Najważniejsze pary form: podmiotowej i dopełnieniowej.",
            "examples": [
                {
                    "en": "I → me",
                    "ua": "I → me"
                },
                {
                    "en": "you → you",
                    "ua": "you → you"
                },
                {
                    "en": "he → him",
                    "ua": "he → him"
                },
                {
                    "en": "she → her",
                    "ua": "she → her"
                },
                {
                    "en": "it → it",
                    "ua": "it → it"
                },
                {
                    "en": "we → us",
                    "ua": "we → us"
                },
                {
                    "en": "they → them",
                    "ua": "they → them"
                }
            ],
            "note": "Subject pronoun stoi zwykle przed czasownikiem, a object pronoun po czasowniku lub przyimku."
        }
    ]
}

{
    "title": "3. Formy dzierżawcze",
    "sections": [
        {
            "label": "Possessive adjectives",
            "color": "blue",
            "description": "<strong>Przymiotniki dzierżawcze</strong> stoją przed rzeczownikiem i pokazują, do kogo coś należy.",
            "examples": [
                {
                    "en": "This is my book.",
                    "ua": "To jest moja książka."
                },
                {
                    "en": "Your car is new.",
                    "ua": "Twój samochód jest nowy."
                },
                {
                    "en": "His name is John.",
                    "ua": "On ma na imię John."
                },
                {
                    "en": "Her sister is a doctor.",
                    "ua": "Jej siostra jest lekarką."
                },
                {
                    "en": "Its color is blue.",
                    "ua": "Jego kolor jest niebieski."
                },
                {
                    "en": "Our house is big.",
                    "ua": "Nasz dom jest duży."
                },
                {
                    "en": "Their dog is cute.",
                    "ua": "Ich pies jest uroczy."
                }
            ],
            "note": "Po tej formie zawsze stoi rzeczownik: <em>my book</em>, <em>their house</em>."
        },
        {
            "label": "Possessive pronouns",
            "color": "sky",
            "description": "<strong>Zaimki dzierżawcze</strong> zastępują cały rzeczownik, więc stoją samodzielnie.",
            "examples": [
                {
                    "en": "This book is mine.",
                    "ua": "Ta książka jest moja."
                },
                {
                    "en": "The car is yours.",
                    "ua": "Samochód jest twój."
                },
                {
                    "en": "That pen is his.",
                    "ua": "Tamten długopis jest jego."
                },
                {
                    "en": "The bag is hers.",
                    "ua": "Ta torba jest jej."
                },
                {
                    "en": "The house is ours.",
                    "ua": "Ten dom jest nasz."
                },
                {
                    "en": "Those keys are theirs.",
                    "ua": "Tamte klucze są ich."
                }
            ],
            "note": "Nie mówimy <em>mine book</em> ani <em>this is my</em>."
        },
        {
            "label": "Its a it's",
            "color": "amber",
            "description": "Nie myl <strong>its</strong> (forma dzierżawcza) z <strong>it's</strong> (= it is).",
            "examples": [
                {
                    "en": "Its color is red.",
                    "ua": "Jego kolor jest czerwony."
                },
                {
                    "en": "It's a cat.",
                    "ua": "To jest kot."
                }
            ],
            "note": "Apostrof pojawia się tylko w skrócie <em>it's</em>."
        }
    ]
}

{
    "title": "4. Zaimki zwrotne",
    "sections": [
        {
            "label": "Formy",
            "color": "purple",
            "description": "Zaimki zwrotne kończą się na <strong>-self</strong> w liczbie pojedynczej i <strong>-selves</strong> w liczbie mnogiej.",
            "examples": [
                {
                    "en": "I → myself",
                    "ua": "I → myself"
                },
                {
                    "en": "you → yourself / yourselves",
                    "ua": "you → yourself / yourselves"
                },
                {
                    "en": "he → himself",
                    "ua": "he → himself"
                },
                {
                    "en": "she → herself",
                    "ua": "she → herself"
                },
                {
                    "en": "it → itself",
                    "ua": "it → itself"
                },
                {
                    "en": "we → ourselves",
                    "ua": "we → ourselves"
                },
                {
                    "en": "they → themselves",
                    "ua": "they → themselves"
                }
            ]
        },
        {
            "label": "Kiedy ich używamy",
            "color": "emerald",
            "description": "Używamy ich wtedy, gdy <strong>podmiot i dopełnienie to ta sama osoba albo rzecz</strong>.",
            "examples": [
                {
                    "en": "I taught myself English.",
                    "ua": "Sam nauczyłem się angielskiego."
                },
                {
                    "en": "She cut herself.",
                    "ua": "Ona się skaleczyła."
                },
                {
                    "en": "We enjoyed ourselves.",
                    "ua": "Świetnie się bawiliśmy."
                },
                {
                    "en": "They did it themselves.",
                    "ua": "Zrobili to sami."
                }
            ]
        },
        {
            "label": "Funkcja wzmacniająca",
            "color": "amber",
            "description": "Zaimki zwrotne mogą też podkreślać, że ktoś zrobił coś <strong>samodzielnie</strong>.",
            "examples": [
                {
                    "en": "I did it myself.",
                    "ua": "Zrobiłem to sam."
                },
                {
                    "en": "The boss himself came.",
                    "ua": "Sam szef przyszedł."
                },
                {
                    "en": "She fixed the car herself.",
                    "ua": "Sama naprawiła samochód."
                }
            ],
            "note": "<em>By myself</em> często znaczy „sam, bez pomocy”."
        }
    ]
}

{
    "title": "5. Zaimki wskazujące",
    "sections": [
        {
            "label": "This / That",
            "color": "blue",
            "description": "<strong>This</strong> odnosi się zwykle do czegoś bliskiego, a <strong>that</strong> do czegoś dalszego.",
            "examples": [
                {
                    "en": "This is my phone.",
                    "ua": "To jest mój telefon."
                },
                {
                    "en": "That is your car.",
                    "ua": "Tamto to twój samochód."
                },
                {
                    "en": "I like this.",
                    "ua": "To mi się podoba."
                },
                {
                    "en": "What is that?",
                    "ua": "Co to jest?"
                }
            ]
        },
        {
            "label": "These / Those",
            "color": "sky",
            "description": "<strong>These</strong> i <strong>those</strong> to liczba mnoga: pierwsza forma zwykle dla rzeczy bliższych, druga dla dalszych.",
            "examples": [
                {
                    "en": "These are my books.",
                    "ua": "To są moje książki."
                },
                {
                    "en": "Those are your keys.",
                    "ua": "Tamto są twoje klucze."
                },
                {
                    "en": "I want these.",
                    "ua": "Chcę te."
                },
                {
                    "en": "Those are expensive.",
                    "ua": "Tamte są drogie."
                }
            ],
            "note": "This / that to liczba pojedyncza, a these / those liczba mnoga."
        }
    ]
}

{
    "title": "6. Inne typy zaimków — krótki przegląd",
    "sections": [
        {
            "label": "Indefinite pronouns",
            "color": "purple",
            "description": "Zaimki nieokreślone odnoszą się do osób albo rzeczy bez wskazywania dokładnie kogo lub czego.",
            "examples": [
                {
                    "en": "Someone is calling.",
                    "ua": "Ktoś dzwoni."
                },
                {
                    "en": "Anybody can do it.",
                    "ua": "Każdy może to zrobić."
                },
                {
                    "en": "Nothing is impossible.",
                    "ua": "Nic nie jest niemożliwe."
                },
                {
                    "en": "Everybody knows that.",
                    "ua": "Wszyscy to wiedzą."
                }
            ]
        },
        {
            "label": "Relative pronouns",
            "color": "emerald",
            "description": "Zaimki względne łączą części zdania złożonego.",
            "examples": [
                {
                    "en": "The man who called is my boss.",
                    "ua": "Mężczyzna, który dzwonił, jest moim szefem."
                },
                {
                    "en": "The book that I read was great.",
                    "ua": "Książka, którą przeczytałem, była świetna."
                },
                {
                    "en": "The car which is red is mine.",
                    "ua": "Samochód, który jest czerwony, jest mój."
                }
            ]
        },
        {
            "label": "Reciprocal pronouns",
            "color": "amber",
            "description": "Zaimki wzajemne pokazują, że dwie lub więcej osób robią coś sobie nawzajem.",
            "examples": [
                {
                    "en": "They love each other.",
                    "ua": "Kochają się nawzajem."
                },
                {
                    "en": "We help one another.",
                    "ua": "Pomagamy sobie nawzajem."
                }
            ],
            "note": "W praktyce <em>each other</em> i <em>one another</em> często się mieszają, ale oba znaczą „nawzajem”."
        }
    ]
}

{
    "title": "7. Tabela podstawowych form zaimków",
    "intro": "Najczęściej spotykane grupy form:",
    "rows": [
        {
            "en": "Subject",
            "ua": "podmiot",
            "note": "I, you, he, she, it, we, they"
        },
        {
            "en": "Object",
            "ua": "dopełnienie",
            "note": "me, you, him, her, it, us, them"
        },
        {
            "en": "Possessive Adj.",
            "ua": "przymiotnik dzierżawczy",
            "note": "my, your, his, her, its, our, their"
        },
        {
            "en": "Possessive Pron.",
            "ua": "zaimek dzierżawczy",
            "note": "mine, yours, his, hers, ours, theirs"
        },
        {
            "en": "Reflexive",
            "ua": "zwrotny",
            "note": "myself, yourself, himself, herself, itself, ourselves, yourselves, themselves"
        }
    ],
    "warning": "📌 Warto od razu uczyć się par: <em>I → me</em>, <em>my → mine</em>, <em>she → her</em>, <em>her → hers</em>."
}

{
    "title": "8. Typowe błędy polskich uczących się",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Mylenie form podmiotowych i dopełnieniowych.",
            "wrong": "Me and John went to the park.",
            "right": "✅ <span class=\"font-mono\">John and I went to the park.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Mylenie its i it's.",
            "wrong": "Its a cat. / The dog wagged it's tail.",
            "right": "✅ <span class=\"font-mono\">It's a cat. / The dog wagged its tail.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Pomijanie zaimka zwrotnego.",
            "wrong": "I taught English.",
            "right": "✅ <span class=\"font-mono\">I taught myself English.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Użycie formy dzierżawczej bez właściwego wzorca.",
            "wrong": "This book is my.",
            "right": "✅ <span class=\"font-mono\">This book is mine.</span>"
        }
    ]
}

{
    "title": "10. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Wybierz poprawny zaimek",
    "select_intro": "Uzupełnij zdanie odpowiednią formą.",
    "selects": [
        {
            "label": "___ am a student. (I / Me)",
            "prompt": "Która forma pasuje?"
        },
        {
            "label": "This book is ___. (my / mine)",
            "prompt": "Która forma pasuje?"
        },
        {
            "label": "She did it ___. (herself / her)",
            "prompt": "Która forma pasuje?"
        },
        {
            "label": "___ is my phone. (This / These)",
            "prompt": "Która forma pasuje?"
        }
    ],
    "options": [
        "I",
        "me",
        "my",
        "mine",
        "myself",
        "this",
        "these",
        "her",
        "herself"
    ],
    "input_title": "Ćwiczenie 2. Wpisz właściwą formę",
    "input_intro": "Wstaw odpowiedni zaimek.",
    "inputs": [
        {
            "before": "___ like music. (I)",
            "after": "→"
        },
        {
            "before": "Give it to ___. (me)",
            "after": "→"
        },
        {
            "before": "This is ___ car. (my)",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błędy",
    "rephrase_intro": "Znajdź i popraw błąd związany z zaimkiem.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Me and John are friends.",
            "example_target": "John and I are friends."
        },
        {
            "original": "1. Its a beautiful day.",
            "placeholder": "Popraw błąd"
        },
        {
            "original": "2. This book is my.",
            "placeholder": "Popraw błąd"
        }
    ]
}

{
    "title": "Kontynuuj naukę",
    "items": [
        {
            "label": "Pronouns — przegląd",
            "current": true
        },
        {
            "label": "Personal / Object Pronouns — formy osobowe i dopełnieniowe",
            "current": false
        },
        {
            "label": "Possessive Adjectives vs Pronouns — my / mine",
            "current": false
        },
        {
            "label": "Reflexive Pronouns — myself, yourself, themselves",
            "current": false
        }
    ]
}
